`,tt(e.p,{children:"We introduce Persona-E², a human-grounded dataset for personality-shaped emotion analysis, and demonstrate that trait-aware modeling—particularly using the Big Five—helps LLMs mitigate ``personality illusion'' in simulating reader appraisals."}),`
`,tt(e.h1,{children:"Abstract"}),`
`,tt(e.p,{children:"Persona-E² is a large-scale dataset designed to explore the complex interplay between persona, events, and emotional responses. Understanding how individual personalities influence emotional reactions to various life events, news, and social media content is crucial for developing more empathetic and human-like AI systems. This dataset provides expert-annotated events coupled with detailed persona profiles and their corresponding emotional states, enabling research into persona-driven emotion prediction and empathetic response generation. Our analysis reveals that persona information significantly enhances the accuracy of emotion prediction models across diverse scenarios."})]})}function uLe(n={}){const{wrapper:e}=n.components||{};return e?tt(e,{...n,children:tt(c9,{...n})}):c9(n)}const dLe={__name:"Abstract",setup(n){return(e,t)=>{const r=Mt("el-divider"),i=Mt("el-col"),a=Mt("el-row");return V(),de("div",null,[oe(r),oe(a,{justify:"center"},{default:be(()=>[oe(i,{xs:24,sm:20,md:16,lg:12,xl:12},{default:be(()=>[oe(x(uLe))]),_:1})]),_:1})])}}};function u9(n){const e={a:"a",h1:"h1",h2:"h2",h3:"h3",img:"img",li:"li",ol:"ol",p:"p",strong:"strong",table:"table",tbody:"tbody",td:"td",th:"th",thead:"thead",tr:"tr",...n.components};return tt(zt,{children:[tt(e.h1,{children:"Introduction"}),`
`,tt(e.p,{children:"The study of affective appraisal of events has long been central to affective computing and cognitive psychology. While appraisal theories suggest that emotions emerge through individualized appraisals shaped by goals and dispositions, NLP research has largely focused on writer-expressed sentiments and reader-based unified emotional labels. This focus overlooks reader-based nuanced perception, which is critical for applications, including empathetic agents, mental health support, and personalized AI assistants."}),`
